import{c as a,Q as s,j as e,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Harness Engineering for Language Agents: The CAR Framework","description":"","frontmatter":{"url":"https://www.preprints.org/manuscript/202603.1756.v2","title":"Harness Engineering for Language Agents: The CAR Framework","date":"2026-04-23T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-23-harness-engineering-car-framework.md","filePath":"research/ai-articles/scored/2026-04-23-harness-engineering-car-framework.md","lastUpdated":1779796674000}'),t={name:"research/ai-articles/scored/2026-04-23-harness-engineering-car-framework.md"};function o(i,n,l,p,g,d){return s(),e("div",null,[...n[0]||(n[0]=[r(`<h1 id="harness-engineering-for-language-agents-the-car-framework" tabindex="-1">Harness Engineering for Language Agents: The CAR Framework <a class="header-anchor" href="#harness-engineering-for-language-agents-the-car-framework" aria-label="Permalink to &quot;Harness Engineering for Language Agents: The CAR Framework&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://www.preprints.org/manuscript/202603.1756.v2" target="_blank" rel="noreferrer">https://www.preprints.org/manuscript/202603.1756.v2</a><br><strong>作者</strong>：Chaoyue He 等 6 位（南洋理工大學）<br><strong>發表日期</strong>：2026-04-23<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題" tabindex="-1">核心命題 <a class="header-anchor" href="#核心命題" aria-label="Permalink to &quot;核心命題&quot;">​</a></h3><p>Language Agent 的可靠性不是來自基礎模型品質或提示詞技術，而是來自「<strong>harness 層</strong>」——決定哪些指令具有權威性、可用動作、狀態持久化方式、跨時間失敗管理的基礎設施。</p><blockquote><p>「許多報告的 Agent 效能提升可能源於 harness 改進，而非純粹的模型能力提升。」</p></blockquote><h3 id="car-分解框架" tabindex="-1">CAR 分解框架 <a class="header-anchor" href="#car-分解框架" aria-label="Permalink to &quot;CAR 分解框架&quot;">​</a></h3><p>論文提出以 <strong>Control（控制）、Agency（代理）、Runtime（執行環境）</strong> 三層分析 harness 結構：</p><hr><h4 id="c-—-control-layer-控制層" tabindex="-1">C — Control Layer（控制層） <a class="header-anchor" href="#c-—-control-layer-控制層" aria-label="Permalink to &quot;C — Control Layer（控制層）&quot;">​</a></h4><p><strong>定義</strong>：執行前編碼行為約束的持久性 artifacts</p><p><strong>典型範例</strong>：</p><ul><li>Repository maps 和導航結構</li><li>AGENTS.md 文件（指定 Agent 角色和能力）</li><li>架構規則和權限政策</li><li>工具描述和介面 schema</li><li>測試套件和驗證程序</li><li>Linting 規則和靜態檢查</li></ul><p><strong>關鍵屬性</strong>：Control 是語言性的且持久的；它透過明確限制可允許動作的空間來塑造 Agent 行為。</p><p><strong>代表性系統</strong>：SWE-agent 的 repository 介面控制、Anthropic 的 Agent 安全指引</p><hr><h4 id="a-—-agency-layer-代理層" tabindex="-1">A — Agency Layer（代理層） <a class="header-anchor" href="#a-—-agency-layer-代理層" aria-label="Permalink to &quot;A — Agency Layer（代理層）&quot;">​</a></h4><p><strong>定義</strong>：Agent 與系統互動的動作基底和介面</p><p><strong>典型範例</strong>：</p><ul><li>程式碼執行環境（沙箱化/非沙箱化）</li><li>瀏覽器自動化介面</li><li>工具 API 及其 schema</li><li>Orchestrator-worker 通訊模式</li><li>審核者角色和核准工作流</li><li>具體的介面定義（如 ReAct 的動作 schema）</li></ul><p><strong>關鍵屬性</strong>：Agency 定義了可能動作的「形狀」。能存取 Python REPL 的 Agent 與只能做 web search 的 Agent 有根本不同的 Agency。</p><p><strong>代表性系統</strong>：SWE-agent 的 CLI 介面、CoOp 的瀏覽器介面</p><hr><h4 id="r-—-runtime-layer-執行環境層" tabindex="-1">R — Runtime Layer（執行環境層） <a class="header-anchor" href="#r-—-runtime-layer-執行環境層" aria-label="Permalink to &quot;R — Runtime Layer（執行環境層）&quot;">​</a></h4><p><strong>定義</strong>：在延伸執行過程中維持系統一致性的時間性治理結構</p><p><strong>典型範例</strong>：</p><ul><li>Context 組裝和優化</li><li>記憶管理（工作記憶、情節記憶、語義記憶）</li><li>狀態持久化和 checkpointing</li><li>重試策略和回溯</li><li>核准工作流和預算執行</li><li>Trace 收集和可觀測性</li></ul><p><strong>關鍵屬性</strong>：Runtime 是執行層。它決定 Agent 如何在管理有限資源（context、計算、時間）的情況下導航長期任務。</p><hr><h3 id="harness-敏感性-為什麼歸因重要" tabindex="-1">Harness 敏感性：為什麼歸因重要 <a class="header-anchor" href="#harness-敏感性-為什麼歸因重要" aria-label="Permalink to &quot;Harness 敏感性：為什麼歸因重要&quot;">​</a></h3><p><strong>已記錄的 harness 效能影響</strong>：</p><ul><li>SWE-agent CLI 介面重新設計改善效能約 40%（無模型改變）</li><li>OS-Symphony 從 code-based → NL harness 遷移大幅改變效能</li><li>Meta-Harness 顯示發現的 harness 優化跨模型遷移</li></ul><p><strong>當前問題</strong>：論文通常只報告改善幅度，不說明來源（模型改進 vs. harness 重設計 vs. 任務特化）。</p><h3 id="_63-篇文獻審計的發現" tabindex="-1">63 篇文獻審計的發現 <a class="header-anchor" href="#_63-篇文獻審計的發現" aria-label="Permalink to &quot;63 篇文獻審計的發現&quot;">​</a></h3><p><strong>學術文獻</strong>強調：介面設計和評估協議、Agent 效能指標、提示詞技術</p><p><strong>工程文件</strong>（Anthropic、OpenAI）強調：執行環境控制和狀態管理、記憶架構、安全治理機制</p><p><strong>差距詮釋</strong>：Harness engineering 在實踐中比在學術發表中更可見，代表其作為研究對象被嚴重低估。</p><h3 id="harnesscard-透明度披露標準" tabindex="-1">HarnessCard：透明度披露標準 <a class="header-anchor" href="#harnesscard-透明度披露標準" aria-label="Permalink to &quot;HarnessCard：透明度披露標準&quot;">​</a></h3><p><strong>動機</strong>：現行實踐模糊 harness 細節，使可重現性和比較困難。HarnessCard 提供輕量披露模板。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## HarnessCard</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**模型**：Claude 3.5 Sonnet, temperature=0.7, max_tokens=2048</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Control**:</span></span>
<span class="line"><span>- 工具存取：檔案讀寫（限 /project/），CLI 執行（命令白名單）</span></span>
<span class="line"><span>- 安全政策：破壞性操作需核准</span></span>
<span class="line"><span>- 測試套件：commit 前 linting 強制執行</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Runtime**:</span></span>
<span class="line"><span>- 記憶：Session 歷史（最後 10K tokens）+ 持久筆記</span></span>
<span class="line"><span>- Context 策略：80% window 使用率時壓縮</span></span>
<span class="line"><span>- 重試預算：每個失敗動作 3 次嘗試</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Agency**:</span></span>
<span class="line"><span>- Shell：/bin/bash 加命令限制</span></span>
<span class="line"><span>- 文件系統：僅限專案目錄</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**評估**:</span></span>
<span class="line"><span>- 指標：SWE-bench Verified（500 任務）的任務成功率</span></span></code></pre></div><h3 id="常見失敗模式-按-agent-類型" tabindex="-1">常見失敗模式（按 Agent 類型） <a class="header-anchor" href="#常見失敗模式-按-agent-類型" aria-label="Permalink to &quot;常見失敗模式（按 Agent 類型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent 類型</th><th>常見失敗</th></tr></thead><tbody><tr><td><strong>Repository coding agents</strong></td><td>Context 漂移——session 時間增加時失去 repository 結構感知</td></tr><tr><td><strong>Browser agents</strong></td><td>Verifier 過擬合——Agent 學會利用評估信號而非真正解決任務</td></tr><tr><td><strong>Enterprise support agents</strong></td><td>政策違反——在長對話中超越授權邊界</td></tr></tbody></table><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><p><strong>CAR = cc-workspace 的 harness 解剖</strong>：</p><ul><li><strong>Control</strong> = CLAUDE.md + rules/ + linter hooks + 工具描述</li><li><strong>Agency</strong> = Sub-agent 類型 + MCP servers + tool 清單</li><li><strong>Runtime</strong> = context-monitor + compact 觸發 + session 記憶</li></ul></li><li><p><strong>HarnessCard 標準</strong>：</p><ul><li>cc-workspace 的每個 Skill 和 Agent 應包含 HarnessCard 格式的元資訊</li><li>這正是 SKILL.md 格式的延伸方向</li></ul></li><li><p><strong>Context 漂移是已知失敗模式</strong>：context-monitor-table.md 的設計就是在對抗這個問題</p></li><li><p><strong>Harness 改進 = 模型升級的替代品</strong>：SWE-agent +40% 的例子支持在選擇升級模型之前先審計 harness</p></li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>CAR 框架可直接用於 cc-workspace 的 harness 審計；HarnessCard 可成為 SKILL.md 的元資訊標準</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>HarnessCard 披露標準和 CAR 三層分解是學術貢獻；可見性不對稱的論點有說服力</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>63 篇文獻的描述性審計；有具體案例（SWE-agent +40%），但為引用而非直接實驗</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>CAR 三層詳細定義、HarnessCard 模板、三種 Agent 類型的失敗模式分析均完整</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>CAR 框架明確設計為跨 Agent 類型、跨任務領域的通用分析框架</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.95/10</strong></td><td>8×0.3 + 8×0.2 + 7×0.2 + 8×0.15 + 9×0.15 = 2.4+1.6+1.4+1.2+1.35</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code>（CAR 框架作為主要分析工具）<br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 harness-design.md 採用 CAR 作為頂層分析框架，取代或補充現有說明</li><li>在 SKILL.md 模板中加入 HarnessCard 元資訊區塊（Control、Agency、Runtime 三段各一行摘要）</li><li>在 context-monitor-table.md 加入「Context 漂移」的 CAR 解釋（Runtime 層失效的典型案例）</li></ul>`,51)])])}const u=a(t,[["render",o]]);export{h as __pageData,u as default};
